import type { Goal, NewGoal } from '@motivation/shared';
import { GoalService } from '../../../services/goal.service.js';

export class GoalDialogController {
    private goalDialog: HTMLDialogElement | null;
    private goalForm: HTMLFormElement | null;
    private confirmDialog: HTMLDialogElement | null;
    private statusDialog: HTMLDialogElement | null;

    private activeGoalForStatus: Goal | null = null;
    private pendingDeleteId: string | null = null;

    private onGoalChanged: () => Promise<void>;

    constructor(onGoalChanged: () => Promise<void>) {
        this.goalDialog = document.getElementById('goal-dialog') as HTMLDialogElement;
        this.goalForm = document.getElementById('goal-form') as HTMLFormElement;
        this.confirmDialog = document.getElementById('confirm-dialog') as HTMLDialogElement;
        this.statusDialog = document.getElementById('status-dialog') as HTMLDialogElement;

        this.onGoalChanged = onGoalChanged;
        this.initEvents();
    }

    private initEvents() {
        this.goalForm?.addEventListener('submit', (e) => e.preventDefault());

        this.goalDialog?.addEventListener('click', async (e) => {
            const target = e.target as HTMLElement;
            if (target.tagName === 'BUTTON' && (target as HTMLButtonElement).value === 'save') {
                e.preventDefault();
                if (!this.goalForm?.checkValidity()) {
                    this.goalForm?.reportValidity();
                    return;
                }
                await this.handleSave();
            } else if (target.tagName === 'BUTTON' && (target as HTMLButtonElement).value === 'cancel') {
                this.goalDialog?.close();
            }
        });

        this.confirmDialog?.addEventListener('click', async (e) => {
            const target = e.target as HTMLElement;
            if (target.tagName === 'BUTTON' && (target as HTMLButtonElement).value === 'confirm') {
                e.preventDefault();
                await this.handleDelete();
            } else if (target.tagName === 'BUTTON' && (target as HTMLButtonElement).value === 'cancel') {
                this.confirmDialog?.close();
            }
        });

        this.statusDialog?.addEventListener('click', async (e) => {
            const target = e.target as HTMLElement;
            if (target.tagName === 'BUTTON' && target.classList.contains('btn-status')) {
                e.preventDefault();
                await this.handleStatusChange((target as HTMLButtonElement).value);
            } else if (target.tagName === 'BUTTON' && (target as HTMLButtonElement).value === 'cancel') {
                this.statusDialog?.close();
            }
        });
    }

    openGoalDialog(goal: Goal | null = null, parentId: string | null = null) {
        if (!this.goalForm || !this.goalDialog) return;
        this.goalForm.reset();

        const idInput = document.getElementById('goal-id') as HTMLInputElement;
        const parentIdInput = document.getElementById('goal-parent-id') as HTMLInputElement;
        const titleInput = document.getElementById('goal-title-input') as HTMLInputElement;
        const statusInput = document.getElementById('goal-status-input') as HTMLSelectElement;
        const descInput = document.getElementById('goal-desc-input') as HTMLTextAreaElement;
        const dialogTitle = document.getElementById('dialog-title');

        if (goal) {
            if (dialogTitle) dialogTitle.textContent = 'Edit Goal';
            idInput.value = goal.id;
            titleInput.value = goal.title;
            statusInput.value = goal.status;
            descInput.value = goal.description ?? '';
            parentIdInput.value = '';
        } else {
            if (dialogTitle) dialogTitle.textContent = 'New Goal';
            idInput.value = '';
            statusInput.value = 'ACTIVE';
            parentIdInput.value = parentId ?? '';
        }
        this.goalDialog.showModal();
    }

    async handleSave() {
        const formData = new FormData(this.goalForm!);
        const id = formData.get('id') as string;
        const parent_id = formData.get('parent_id') as string;
        const title = formData.get('title') as string;
        const status = formData.get('status') as string;
        const description = formData.get('description') as string;

        const payload: NewGoal | Partial<Goal> = { title, description, status: status as Goal['status'] };
        if (parent_id) payload.parent_id = parent_id;

        if (id) {
            await GoalService.updateGoal(id, payload);
        } else {
            await GoalService.createGoal(payload as NewGoal);
        }
        this.goalDialog?.close();
        await this.onGoalChanged();
    }

    openConfirmDelete(id: string) {
        this.pendingDeleteId = id;
        this.confirmDialog?.showModal();
    }

    async handleDelete() {
        if (!this.pendingDeleteId) return;
        await GoalService.deleteGoal(this.pendingDeleteId);
        this.confirmDialog?.close();
        this.pendingDeleteId = null;
        await this.onGoalChanged();
    }

    openStatusDialog(goal: Goal) {
        this.activeGoalForStatus = goal;
        this.statusDialog?.showModal();
    }

    async handleStatusChange(newStatus: string) {
        if (!this.activeGoalForStatus) return;
        const goal = this.activeGoalForStatus;

        await GoalService.updateGoal(goal.id, {
            status: newStatus as Goal['status']
        });

        this.statusDialog?.close();
        this.activeGoalForStatus = null;
        await this.onGoalChanged();
    }
}
